@namespace Lumeo

@* Render the label, control and helper/error as ONE self-contained vertical block so the
   field never splays into a row when dropped in a flex / centered container. Standalone
   form-field structural fix. *@
<div class="flex flex-col items-start">
@if (Label is not null && !InsideFormField)
{
    <label for="@EffectiveId" class="text-sm font-medium leading-none">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

<div class="inline-flex items-center">
    <button type="button" id="@EffectiveId" role="switch"
            aria-checked="@_checked.ToString().ToLower()"
            aria-label="@AriaLabelValue"
            aria-required="@Required.ToString().ToLower()"
            aria-invalid="@EffectiveInvalid.ToString().ToLower()"
            aria-busy="@Loading.ToString().ToLower()"
            aria-describedby="@FormFieldDescribedBy"
            data-state="@DataState"
            data-disabled="@(Disabled ? string.Empty : null)"
            class="@CssClass"
            @onclick="Toggle"
            disabled="@(Disabled || Loading)"
            @attributes="EffectiveAttributes">
        <span class="@ThumbClasses" data-state="@DataState">
            @if (Loading)
            {
                @* aria-hidden so the spinner's own role=status / aria-label="Loading"
                   doesn't leak into the switch button's accessible name; aria-busy on
                   the button already announces the in-flight state to AT. *@
                <Spinner Size="Lumeo.Size.Sm" Class="@ThumbSpinnerClass" aria-hidden="true" />
            }
        </span>
    </button>
    @* Bubble input (Radix pattern): visually-hidden, non-focusable native checkbox
       that mirrors the switch state and carries Name/Value so the switch submits in a
       plain <form> POST (a <button name> posts nothing). aria-hidden + tabindex=-1
       keep it out of the a11y tree and tab order. Rendered when a Name is set directly OR
       inherited from a composing <FormField Name="..."> (EffectiveName), so a switch
       composed via FormField still posts its value.
       disabled mirrors the visible button's gate (Disabled || Loading): while Loading
       the button is disabled, so the bubble input must be too or the switch could still
       submit its value in a native form POST mid-load (P2). *@
    @if (!string.IsNullOrEmpty(EffectiveName))
    {
        <input type="checkbox" aria-hidden="true" tabindex="-1"
               name="@EffectiveName" value="@EffectiveValue"
               checked="@_checked"
               disabled="@(Disabled || Loading)" required="@Required"
               class="pointer-events-none absolute -translate-x-full opacity-0"
               style="clip: rect(0 0 0 0); clip-path: inset(50%); overflow: hidden; white-space: nowrap;" />
    }
    @if (HasOnOffLabel)
    {
        <span class="text-xs text-muted-foreground ms-2">@CurrentOnOffLabel</span>
    }
</div>

@if (!InsideFormField)
{
    @if (EffectiveInvalid && ErrorText is not null)
    {
        <p class="text-xs text-destructive" role="alert" aria-live="polite">@ErrorText</p>
    }
    else if (HelperText is not null)
    {
        <p class="text-xs text-muted-foreground">@HelperText</p>
    }
}
</div>

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    /// <summary>Marks the field as required, setting <c>aria-required</c> and (outside a <c>FormField</c>) the bubble checkbox's <c>required</c>, plus appending a destructive-colored asterisk to the label.</summary>
    [Parameter] public bool Required { get; set; }

    /// <summary>Forces the invalid/error visual state (destructive ring) and <c>aria-invalid</c>, independent of the ambient <c>FormField</c>'s validation state.</summary>
    [Parameter] public bool Invalid { get; set; }

    /// <summary>Error message shown below the switch (outside a <c>FormField</c>) when <see cref="Invalid"/> is set. Takes precedence over <see cref="HelperText"/>.</summary>
    [Parameter] public string? ErrorText { get; set; }

    /// <summary>Helper text shown below the switch (outside a <c>FormField</c>) when there is no error to display.</summary>
    [Parameter] public string? HelperText { get; set; }

    /// <summary>Label text rendered before the switch (outside a <c>FormField</c>, which supplies its own label), linked via <c>for</c>/<c>id</c> so clicking it toggles the switch.</summary>
    [Parameter] public string? Label { get; set; }

    /// <summary>HTML <c>name</c> for the hidden bubble checkbox that mirrors the switch state, so it posts in a native <c>&lt;form&gt;</c> (a plain <c>&lt;button&gt;</c> posts nothing). Falls back to a composing <c>FormField</c>'s <c>Name</c> when unset.</summary>
    [Parameter] public string? Name { get; set; }

    /// <summary>
    /// Value submitted for this switch in a native <c>&lt;form&gt;</c> POST when
    /// <see cref="Name"/> is set and the switch is on. Mirrors the native checkbox
    /// default of <c>"on"</c>.
    /// </summary>
    [Parameter] public string? Value { get; set; }

    private string EffectiveValue => Value ?? "on";

    // Field name for the bubble input: a direct Name wins, else the name cascaded by a
    // composing <FormField Name="...">. Lets `<FormField Name="x"><Switch/></FormField>`
    // post the switch value without repeating the name on the Switch (Codex round-3 P2).
    private string? EffectiveName => string.IsNullOrEmpty(Name) ? FormField?.Name : Name;

    // shadcn/Radix data-state styling hook: consumers can target
    // data-[state=checked] / data-[state=unchecked] in CSS.
    private string DataState => _checked ? "checked" : "unchecked";

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    // Inside a FormField, adopt its generated ControlId so the field's <Label For>
    // resolves to this switch button; aria-describedby announces help/error text.
    private string? FormFieldControlId => string.IsNullOrEmpty(FormField?.ControlId) ? null : FormField!.ControlId;
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    // Links the visible <label for> to the switch button (Checkbox pattern) so
    // clicking the label toggles the switch and AT announces the association.
    private readonly string _id = LumeoIds.New("switch");
    // Inside a FormField the generated FormFieldControlId must own the button's id so
    // the <label for> and <button id> always agree. A consumer-splatted id in
    // AdditionalAttributes would otherwise win (splat renders after the explicit attr)
    // and orphan the label. Outside a FormField a consumer-supplied id still wins via
    // LumeoIds.Effective so the standalone label's `for` stays in sync.
    private string EffectiveId => InsideFormField
        ? (FormFieldControlId ?? _id)
        : LumeoIds.Effective(AdditionalAttributes, _id);

    // Strip a consumer-supplied id from the splat when inside a FormField so the
    // generated EffectiveId on the button element cannot be overridden by @attributes.
    private Dictionary<string, object>? EffectiveAttributes =>
        InsideFormField && AdditionalAttributes?.ContainsKey("id") == true
            ? AdditionalAttributes.Where(kv => kv.Key != "id").ToDictionary(kv => kv.Key, kv => kv.Value)
            : AdditionalAttributes;

    /// <summary>Whether the switch is on. Controlled together with <see cref="CheckedChanged"/>; when left unbound the switch tracks its own toggles internally.</summary>
    [Parameter] public bool Checked { get; set; }

    /// <summary>Fires when the user toggles the switch, with the new checked state.</summary>
    [Parameter] public EventCallback<bool> CheckedChanged { get; set; }

    // Uncontrolled state guard (state-on-data-change). The live checked state
    // lives in _checked, NEVER in the [Parameter] Checked. We reseed _checked
    // from the parent ONLY when it genuinely changes the Checked value it
    // supplies (first observation, or a different literal than last time), so a
    // plain parent re-render that re-pushes the same Checked literal no longer
    // clobbers the user's toggle. A genuinely new Checked value still wins. This
    // mirrors the Radix/Base UI controlled-vs-uncontrolled disambiguation a bool
    // param cannot be "undefined", so we inspect which parameters were provided.
    private bool _checked;
    private bool _lastCheckedParam;
    // CONTROLLED discriminator: the last value we pushed UP via CheckedChanged (also
    // re-synced whenever we adopt an authoritative Checked). A controlled parent re-render
    // that echoes back this exact value is safe to ignore (keep in-flight state); any other
    // value is an authoritative assertion (normalization / veto / reset) and must win.
    private bool _lastPushed;
    private bool _hasCheckedParam;

    public override Task SetParametersAsync(ParameterView parameters)
    {
        // Seed _checked and both discriminators from the incoming parameter BEFORE
        // base.SetParametersAsync triggers the initial render, so the first painted
        // frame already reflects the correct checked state.
        if (!_hasCheckedParam && parameters.TryGetValue<bool>(nameof(Checked), out var incoming))
        {
            _checked = incoming;
            _lastCheckedParam = incoming;
            _lastPushed = incoming;
            _hasCheckedParam = true;
        }

        return base.SetParametersAsync(parameters);
    }

    protected override void OnParametersSet()
    {
        if (!_hasCheckedParam) return;

        if (CheckedChanged.HasDelegate)
        {
            // CONTROLLED: the parent owns the value.
            // Echo of our own push (Checked == _lastPushed) → keep in-flight backing state.
            // Anything else (veto, normalization, reset) → adopt the parent's assertion.
            if (Checked != _lastPushed)
            {
                _checked = Checked;
                _lastPushed = Checked;
            }
        }
        else if (Checked != _lastCheckedParam)
        {
            // UNCONTROLLED: component owns the live value.
            // Adopt the parameter only when the parent genuinely changes it; a stale
            // re-render that re-supplies the same literal must not clobber the user's toggle.
            _checked = Checked;
            _lastPushed = Checked;
        }

        // Keep the uncontrolled discriminator pointing at the last Checked we observed.
        _lastCheckedParam = Checked;
    }
    /// <summary>When <c>true</c>, the switch cannot be toggled and renders with reduced opacity.</summary>
    [Parameter] public bool Disabled { get; set; }

    /// <summary>When <c>true</c>, shows a small spinner in the thumb, disables toggling, and sets <c>aria-busy</c> — for an in-flight async state change.</summary>
    [Parameter] public bool Loading { get; set; }

    /// <summary>Text shown next to the switch (and used as a fallback accessible name) while it is on.</summary>
    [Parameter] public string? OnLabel { get; set; }

    /// <summary>Text shown next to the switch (and used as a fallback accessible name) while it is off.</summary>
    [Parameter] public string? OffLabel { get; set; }
    /// <summary>
    /// Accessible name for the switch button, exposed via <c>aria-label</c>. Recommended
    /// for icon-only switches that have no visible text. If omitted but
    /// <see cref="OnLabel"/>/<see cref="OffLabel"/> are set, the current one is
    /// used automatically so screen readers announce the switch's purpose.
    /// </summary>
    [Parameter] public string? AriaLabel { get; set; }
    /// <summary>Switch size. Supports <see cref="Lumeo.Size.Sm"/>,
    /// <see cref="Lumeo.Size.Md"/> (default), <see cref="Lumeo.Size.Lg"/>.</summary>
    [Parameter] public Lumeo.Size Size { get; set; } = Lumeo.Size.Md;

    /// <summary>
    /// When true, the thumb animates with a bouncy spring cubic-bezier timing
    /// instead of the default linear transition. Default is <c>false</c>.
    /// </summary>
    [Parameter] public bool Animated { get; set; }

    /// <summary>
    /// When true, triggers a short haptic vibration via <c>navigator.vibrate()</c>
    /// each time the switch is toggled. Silently no-ops on browsers without the
    /// Vibration API (e.g. iOS Safari). Default is <c>false</c>.
    /// </summary>
    [Parameter] public bool HapticFeedback { get; set; }

    [Inject] private HapticsService Haptics { get; set; } = default!;

    /// <summary>Additional CSS classes merged onto the switch's track <c>button</c>.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the switch's track <c>button</c> (a splatted <c>id</c> is stripped inside a <c>FormField</c> so the generated id keeps the label wired up).</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool HasOnOffLabel => OnLabel != null || OffLabel != null;
    private string? CurrentOnOffLabel => _checked ? OnLabel : OffLabel;

    // Prefer an explicit AriaLabel, then fall back to the currently visible On/Off text, then to Label
    // so even consumers who don't set AriaLabel get a reasonable screen-reader announcement.
    private string? AriaLabelValue => AriaLabel ?? CurrentOnOffLabel ?? Label;

    private string TrackSizeClasses => Size switch
    {
        Lumeo.Size.Sm => "h-4 w-7",
        Lumeo.Size.Lg => "h-6 w-11",
        _ => "h-5 w-9"
    };

    private string ThumbSizeClasses => Size switch
    {
        Lumeo.Size.Sm => "h-3 w-3",
        Lumeo.Size.Lg => "h-5 w-5",
        _ => "h-4 w-4"
    };

    private string ThumbTranslateClass => Size switch
    {
        Lumeo.Size.Sm => _checked ? "translate-x-3" : "translate-x-0",
        Lumeo.Size.Lg => _checked ? "translate-x-5" : "translate-x-0",
        _ => _checked ? "translate-x-4" : "translate-x-0"
    };

    private string ThumbSpinnerClass => Size switch
    {
        Lumeo.Size.Sm => "!h-2 !w-2",
        Lumeo.Size.Lg => "!h-3.5 !w-3.5",
        _ => "!h-3 !w-3"
    };

    // rounded-[calc(var(--radius)*2)] instead of a hardcoded full pill: the theme's
    // radius token now reaches the Switch. At every stock radius (0.75rem default → 24px,
    // even a 0.5rem theme → 16px) the computed radius exceeds half the track height of
    // ALL sizes (Sm h-4/8px … Lg h-6/12px), so CSS corner-overlap reduction renders the
    // exact same full pill as before — pixel-identical default. Only a deliberately sharp
    // theme (small/zero --radius) squares the Switch off along with everything else;
    // previously it stayed a pill in an otherwise square UI (user-reported inconsistency).
    // Note: stock shadcn keeps its Switch a hard pill regardless of radius — this is a
    // deliberate divergence in favor of theme consistency. The *2 factor (not the *1.5 of
    // --radius-xl) is what keeps the 0.5rem-radius case a true pill on the Lg track.
    private string CssClass => Cx.Merge(
        "peer inline-flex",
        TrackSizeClasses,
        "shrink-0 cursor-pointer items-center rounded-[calc(var(--radius)*2)] border-2 border-transparent shadow-sm transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50",
        _checked ? "bg-primary" : "bg-input",
        Cx.When(EffectiveInvalid, "ring-2 ring-destructive/20 focus-visible:ring-destructive"),
        Cx.When(Loading, "pointer-events-none opacity-70"),
        Class);

    private string ThumbClasses
    {
        get
        {
            var springClass = Animated ? "lumeo-switch-spring" : null;
            return Cx.Join(
                "pointer-events-none flex items-center justify-center",
                ThumbSizeClasses,
                // Same radius-token mapping as the track (see CssClass) — a circular thumb
                // in a squared track would look just as inconsistent as the old pill.
                "rounded-[calc(var(--radius)*2)] bg-background shadow-sm ring-0 transition-transform",
                ThumbTranslateClass,
                springClass);
        }
    }

    private async Task Toggle()
    {
        if (!Disabled && !Loading)
        {
            // Mutate the working backing field only — NEVER the [Parameter] Checked.
            // Record _lastPushed BEFORE invoking CheckedChanged: a controlled parent
            // re-renders synchronously inside InvokeAsync, so OnParametersSet must already
            // see this value as "the value we just pushed" to distinguish an accepted echo
            // (keep in-flight state) from a veto (parent kept its old value → roll back).
            _checked = !_checked;
            _lastPushed = _checked;
            await CheckedChanged.InvokeAsync(_checked);
            if (HapticFeedback) await Haptics.Light();
        }
    }

}
